function maxPoints(points) {
    const n = points.length;
    if (n <= 2) return n;

    let maxCount = 0;

    for (let i = 0; i < n; i++) {
        const slopeMap = new Map();
        let duplicates = 0, localMax = 0;

        for (let j = i + 1; j < n; j++) {
            let deltaX = points[j][0] - points[i][0];
            let deltaY = points[j][1] - points[i][1];

            if (deltaX === 0 && deltaY === 0) {
                duplicates++;
                continue;
            }

            const gcdVal = gcd(deltaX, deltaY);
            deltaX /= gcdVal;
            deltaY /= gcdVal;

            const key = `${deltaX}_${deltaY}`;
            slopeMap.set(key, (slopeMap.get(key) || 0) + 1);
            localMax = Math.max(localMax, slopeMap.get(key));
        }
        maxCount = Math.max(maxCount, localMax + duplicates + 1);
    }

    return maxCount;
}

function gcd(a, b) {
    if (b === 0) return a;
    return gcd(b, a % b);
}
```


    - Loop through all pairs of points.
- Calculate the slope of the line determined by the two points `(deltaX / deltaY)`, as well as the number of duplicates of the same point.
- Count the occurrences of each unique slope (i.e., the lines that go through the same two points), using a hashmap.
- For each point, find the highest number of slopes and add the duplicates and itself to the count.
- Find the maximum count of all points, which is the answer.

